tree.$.user({ age: 37 });    // { name: 'Bo', age: 37 }`;ngrxCounterCode=`// counter.actions.ts
export const increment = createAction('[Counter] Increment');
export const reset = createAction('[Counter] Reset');

// counter.reducer.ts
export const counterReducer = createReducer(
  0,
  on(increment, (state) => state + 1),
  on(reset, () => 0)
);

// counter.selectors.ts
export const selectCount = createFeatureSelector<number>('count');

// counter.component.ts
@Component({ /* ... */ })
export class CounterComponent {
  count$ = this.store.select(selectCount);
  constructor(private store: Store) {}
  inc() { this.store.dispatch(increment()); }
  reset() { this.store.dispatch(reset()); }
}`;signalTreeCounterCode=`// counter.tree.ts
